const workflows = $input.all();
const now = new Date().toISOString();

return workflows.map(w => ({
  json: {
    n8n_id: w.id,
    name: w.name,
    active: w.active,
    tags: w.tags || [],
    status: w.active ? 'active' : 'inactive',
    updated_at: now
  }
}));

const workflow = $input.first().json;
const executions = $('Execuções (24h)').all();

const now = new Date();
const dayAgo = new Date(now.getTime() - 24 * 60 * 60 * 1000);

const recent = executions.filter(e => new Date(e.startedAt || e.createdAt) >= dayAgo);
const success = recent.filter(e => e.finished && e.status === 'success').length;
const errors = recent.filter(e => e.status === 'error' || e.stoppedAt).length;
const total = recent.length;
const durations = recent.filter(e => e.executionTime).map(e => e.executionTime);
const avg = durations.length ? Math.round(durations.reduce((a,b) => a + b, 0) / durations.length) : null;

const lastExec = recent.length ? recent.sort((a,b) => new Date(b.startedAt || b.createdAt) - new Date(a.startedAt || a.createdAt))[0] : null;

return [{
  json: {
    n8n_id: workflow.n8n_id,
    name: workflow.name,
    active: workflow.active,
    tags: workflow.tags,
    status: workflow.status,
    last_execution_status: lastExec ? lastExec.status : null,
    last_executed_at: lastExec ? (lastExec.startedAt || lastExec.createdAt) : null,
    last_execution_id: lastExec ? lastExec.id : null,
    executions_24h: total,
    success_24h: success,
    error_24h: errors,
    avg_execution_ms: avg ? Math.round(avg) : null,
    updated_at: now.toISOString()
  }
}];
